from typing import List

def length_of_lis(nums: List[int]) -> int:
    n = len(nums)
    dp = [1] * n  # dp[i] = LIS length ending at index i

    for i in range(1, n):
        for j in range(i):
            if nums[j] < nums[i]:
                dp[i] = max(dp[i], dp[j] + 1)

    return max(dp)

from typing import List
import bisect

def length_of_lis(nums: List[int]) -> int:
    # tails[i] = smallest tail element of all IS of length i+1
    tails = []

    for num in nums:
        pos = bisect.bisect_left(tails, num)
        if pos == len(tails):
            tails.append(num)
        else:
            tails[pos] = num

    return len(tails)
